1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  items: Item[];
14	}
15	
16	export interface QuoteResult {
17	  premium: number;
18	}
19	
20	export interface Damage {
21	  itemType: string;
22	  amount: number;
23	}
24	
25	export interface Incident {
26	  cause: string;
27	  damages: Damage[];
28	}
29	
30	export interface ClaimResult {
31	  payout: number;
32	  remainingCap: number;
33	}
34	
35	// Runes and moonstones are "components" — a distinct pricing tier that shares
36	// one base premium (and, later, block/alike rules). Naming the shared value
37	// makes the equality intentional rather than a coincidence two entries happen
38	// to share.
39	const COMPONENT_BASE_PREMIUM = 25;
40	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
41	// A "building block" of exactly this many alike components is offered at a
42	// special block premium instead of the per-component price.
43	const COMPONENT_BLOCK_SIZE = 3;
44	const COMPONENT_BLOCK_PREMIUM = 60;
45	
46	const BASE_PREMIUMS: Record<string, number> = {
47	  sword: 100,
48	  amulet: 60,
49	  staff: 80,
50	  potion: 40,
51	  rune: COMPONENT_BASE_PREMIUM,
52	  moonstone: COMPONENT_BASE_PREMIUM,
53	};
54	const PROCESSING_FEE = 5;
55	
56	// Insurance values per item type. Unlike base premiums, these are never
57	// discounted (the component block discount affects the premium only, not the
58	// insured value), so each item contributes its full value to the policy's
59	// insurance sum.
60	const COMPONENT_INSURANCE_VALUE = 250;
61	const INSURANCE_VALUES: Record<string, number> = {
62	  sword: 1000,
63	  amulet: 600,
64	  staff: 800,
65	  potion: 400,
66	  rune: COMPONENT_INSURANCE_VALUE,
67	  moonstone: COMPONENT_INSURANCE_VALUE,
68	};
69	// The total payout per policy is capped at twice the insurance sum.
70	const CAP_MULTIPLE = 2;
71	
72	// Surcharges are expressed as integer percentages and applied as
73	// `amount * percent / 100`, keeping the maths in integers (avoids float errors
74	// such as `100 * 1.1 === 100.00000000000001`).
75	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
76	const CURSE_SURCHARGE_PERCENT = 50;
77	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
78	const HIGH_ENCHANTMENT_MIN_LEVEL = 5;
79	const LOYALTY_DISCOUNT_PERCENT = 20;
80	const LOYALTY_MIN_YEARS = 2;
81	const FOLLOWUP_CONTRACT_DISCOUNT_PERCENT = 15;
82	const FIRST_CONTRACT_INDEX = 0;
83	const DEDUCTIBLE = 100;
84	const HIGH_ENCHANTMENT_CLAIM_MIN_LEVEL = 8;
85	const HIGH_ENCHANTMENT_REIMBURSEMENT_PERCENT = 50;
86	
87	// Sum a numeric measure over a list. Centralises the
88	// `reduce((total, x) => total + f(x), 0)` shape shared by every per-item /
89	// per-damage total in this module, so each caller states only *what* it sums.
90	const sumBy = <T>(items: T[], measure: (item: T) => number): number =>
91	  items.reduce((total, item) => total + measure(item), 0);
92	
93	const percentOf = (amount: number, percent: number): number =>
94	  (amount * percent) / 100;
95	
96	// A surcharge that applies only when a condition holds, expressed as a
97	// percentage of some base amount (and 0 otherwise).
98	const conditionalPercent = (
99	  applies: boolean,
100	  amount: number,
101	  percent: number,
102	): number => (applies ? percentOf(amount, percent) : 0);
103	
104	// The base premium for a given item type, with unknown types priced at 0.
105	// This is the single point that reads BASE_PREMIUMS, so both per-item and
106	// per-group pricing share one definition of "the base price of a type".
107	const basePremiumForType = (type: string): number => BASE_PREMIUMS[type] ?? 0;
108	
109	// An item's effective enchantment level, with an absent enchantment treated as
110	// 0. Centralising the default keeps "unenchanted counts as level 0" in one
111	// place for every threshold check (quote surcharge at 5, claim 50% at 8).
112	const enchantmentLevel = (item: Item): number => item.enchantment ?? 0;
113	
114	// A single item's base premium. Block pricing is a group-level concern handled
115	// separately in sumBasePremiums, so a plain per-type lookup suffices here.
116	const itemBasePremium = (item: Item): number => basePremiumForType(item.type);
117	
118	const isKnownItemType = (type: string): boolean => type in BASE_PREMIUMS;
119	
120	// Reject the first element that fails a validity predicate. Centralises the
121	// "scan a list, throw on the first invalid element" shape shared by the quote
122	// and claim guards, so each caller states only *what* is valid and *why* an
123	// invalid element is rejected.
124	const assertEach = <T>(
125	  items: T[],
126	  isValid: (item: T) => boolean,
127	  message: (item: T) => string,
128	): void => {
129	  for (const item of items) {
130	    if (!isValid(item)) {
131	      throw new Error(message(item));
132	    }
133	  }
134	};
135	
136	// A quote can only price item types it has a base premium for, so an unknown
137	// type is rejected up front rather than silently priced at 0. Named so the
138	// quote body reads "reject unknown types, then price" instead of spelling the
139	// scan out inline.
140	const assertKnownItemTypes = (items: Item[]): void =>
141	  assertEach(
142	    items,
143	    (item) => isKnownItemType(item.type),
144	    (item) => `unknown item type: ${item.type}`,
145	  );
146	
147	// Item-specific surcharges, each a percentage of the item's own base premium:
148	// a curse adds 50%, and a highly-enchanted item (level >= 5) adds 30%. They
149	// stack when both apply.
150	const itemSurcharge = (item: Item): number => {
151	  const base = itemBasePremium(item);
152	  const curse = conditionalPercent(
153	    item.cursed ?? false,
154	    base,
155	    CURSE_SURCHARGE_PERCENT,
156	  );
157	  const highEnchantment = conditionalPercent(
158	    enchantmentLevel(item) >= HIGH_ENCHANTMENT_MIN_LEVEL,
159	    base,
160	    HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
161	  );
162	  return curse + highEnchantment;
163	};
164	
165	const sumItemSurcharges = (items: Item[]): number =>
166	  sumBy(items, itemSurcharge);
167	
168	const countByType = (items: Item[]): Map<string, number> => {
169	  const counts = new Map<string, number>();
170	  for (const item of items) {
171	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
172	  }
173	  return counts;
174	};
175	
176	const componentGroupPremium = (count: number): number =>
177	  count === COMPONENT_BLOCK_SIZE
178	    ? COMPONENT_BLOCK_PREMIUM
179	    : count * COMPONENT_BASE_PREMIUM;
180	
181	const typeGroupPremium = (type: string, count: number): number =>
182	  COMPONENT_TYPES.has(type)
183	    ? componentGroupPremium(count)
184	    : count * basePremiumForType(type);
185	
186	const sumBasePremiums = (items: Item[]): number =>
187	  sumBy([...countByType(items)], ([type, count]) =>
188	    typeGroupPremium(type, count),
189	  );
190	
191	// Policy-wide modifiers scale with the whole policy's base premium.
192	// First-insurance is a surcharge every new policy pays; the loyalty discount
193	// rewards customers at or past the loyalty threshold.
194	const firstInsuranceSurcharge = (policyBase: number): number =>
195	  percentOf(policyBase, FIRST_INSURANCE_SURCHARGE_PERCENT);
196	
197	const loyaltyDiscount = (customer: Customer, policyBase: number): number =>
198	  customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS
199	    ? percentOf(policyBase, LOYALTY_DISCOUNT_PERCENT)
200	    : 0;
201	
202	// Every contract after the customer's first quote in the scenario is a
203	// follow-up contract and earns a discount.
204	const followUpDiscount = (quoteIndex: number, policyBase: number): number =>
205	  quoteIndex > FIRST_CONTRACT_INDEX
206	    ? percentOf(policyBase, FOLLOWUP_CONTRACT_DISCOUNT_PERCENT)
207	    : 0;
208	
209	// Net signed adjustment that policy-wide modifiers make to the policy base:
210	// the first-insurance surcharge adds, the loyalty and follow-up discounts
211	// subtract. Grouping them keeps the quote formula at "base + item surcharges
212	// + policy-wide adjustments + fee".
213	const policyAdjustments = (
214	  customer: Customer,
215	  quoteIndex: number,
216	  policyBase: number,
217	): number =>
218	  firstInsuranceSurcharge(policyBase) -
219	  loyaltyDiscount(customer, policyBase) -
220	  followUpDiscount(quoteIndex, policyBase);
221	
222	export const quote = (
223	  customer: Customer,
224	  step: QuoteStep,
225	  quoteIndex: number,
226	): QuoteResult => {
227	  assertKnownItemTypes(step.items);
228	  const policyBase = sumBasePremiums(step.items);
229	  const premium = Math.ceil(
230	    policyBase +
231	      sumItemSurcharges(step.items) +
232	      policyAdjustments(customer, quoteIndex, policyBase) +
233	      PROCESSING_FEE,
234	  );
235	  return { premium };
236	};
237	
238	// The payout cap for a policy: twice the sum of its items' insurance values.
239	// Unknown types are rejected, mirroring quote, so a policy's cap is only
240	// computed from recognised items.
241	export const policyCap = (items: Item[]): number => {
242	  assertKnownItemTypes(items);
243	  const insuranceSum = sumBy(items, (item) => INSURANCE_VALUES[item.type] ?? 0);
244	  return CAP_MULTIPLE * insuranceSum;
245	};
246	
247	// Reimbursement for one damage before the deductible. A highly-enchanted item
248	// (level >= 8) is reimbursed at 50% of the damage; otherwise in full.
249	const reimbursement = (item: Item, damage: Damage): number =>
250	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_CLAIM_MIN_LEVEL
251	    ? percentOf(damage.amount, HIGH_ENCHANTMENT_REIMBURSEMENT_PERCENT)
252	    : damage.amount;
253	
254	// Payout for one damage: the reimbursement minus the deductible, never below 0.
255	const damagePayout = (item: Item, damage: Damage): number =>
256	  Math.max(0, reimbursement(item, damage) - DEDUCTIBLE);
257	
258	// Removes and returns the first policy item insuring this damage's type. Each
259	// damage consumes a distinct insured item, so a claim with more damages of a
260	// type than the policy covers leaves a damage unmatched — which is rejected.
261	const takeInsuredItem = (available: Item[], damage: Damage): Item => {
262	  const index = available.findIndex((item) => item.type === damage.itemType);
263	  if (index < 0) {
264	    throw new Error(
265	      `damage references item not covered by policy: ${damage.itemType}`,
266	    );
267	  }
268	  return available.splice(index, 1)[0];
269	};
270	
271	const assertNonNegativeDamages = (damages: Damage[]): void =>
272	  assertEach(
273	    damages,
274	    (damage) => damage.amount >= 0,
275	    (damage) => `damage amount must not be negative: ${damage.amount}`,
276	  );
277	
278	// Total payout requested across all damages, before the cap. Each damage
279	// consumes a distinct insured item from a private copy of the policy, so the
280	// loop is explicit: takeInsuredItem mutates `available` as it goes, and a plain
281	// accumulator keeps that consume-as-you-go ordering visible (rather than hiding
282	// the side effect inside a pure-looking sumBy).
283	const requestedPayout = (policyItems: Item[], damages: Damage[]): number => {
284	  const available = [...policyItems];
285	  let requested = 0;
286	  for (const damage of damages) {
287	    requested += damagePayout(takeInsuredItem(available, damage), damage);
288	  }
289	  return requested;
290	};
291	
292	export const claim = (
293	  policyItems: Item[],
294	  incident: Incident,
295	  remainingCap: number,
296	): ClaimResult => {
297	  assertNonNegativeDamages(incident.damages);
298	  const requested = requestedPayout(policyItems, incident.damages);
299	  const payout = Math.floor(Math.min(requested, remainingCap));
300	  return { payout, remainingCap: remainingCap - payout };
301	};
