1	import {
2	  quote,
3	  claim,
4	  policyCap,
5	  type Customer,
6	  type Item,
7	  type Incident,
8	} from "./claim-office.js";
9	
10	// Minimal ambient declaration for the Node `process` global used below. The
11	// project does not depend on @types/node, so we declare just the surface this
12	// CLI touches rather than pulling in the full type package.
13	interface ReadableStream {
14	  setEncoding(encoding: string): void;
15	  on(event: "data", listener: (chunk: string) => void): void;
16	  on(event: "end", listener: () => void): void;
17	  on(event: "error", listener: (error: unknown) => void): void;
18	}
19	interface WritableStream {
20	  write(text: string): void;
21	}
22	declare const process: {
23	  stdin: ReadableStream;
24	  stdout: WritableStream;
25	  stderr: WritableStream;
26	  exit(code: number): never;
27	};
28	
29	interface QuoteStepInput {
30	  op: "quote";
31	  items: Item[];
32	}
33	
34	interface ClaimStepInput {
35	  op: "claim";
36	  policy: number;
37	  incident: Incident;
38	}
39	
40	type Step = QuoteStepInput | ClaimStepInput;
41	
42	interface Scenario {
43	  customer: Customer;
44	  steps: Step[];
45	}
46	
47	type Result = { premium: number } | { payout: number; remainingCap: number };
48	
49	// The state a quote step leaves behind for later claim steps to draw on: the
50	// insured items (needed to reimburse damages) and the cap remaining after any
51	// prior claims against this policy.
52	interface Policy {
53	  items: Item[];
54	  remainingCap: number;
55	}
56	
57	const readStdin = (): Promise<string> =>
58	  new Promise((resolve, reject) => {
59	    let input = "";
60	    process.stdin.setEncoding("utf8");
61	    process.stdin.on("data", (chunk) => (input += chunk));
62	    process.stdin.on("end", () => resolve(input));
63	    process.stdin.on("error", reject);
64	  });
65	
66	// Runs the scenario, processing steps in order. Quote steps create a policy and
67	// advance the customer's quote count (each quote after the first is a follow-up
68	// contract); claim steps draw on the policy created by an earlier quote step,
69	// carrying its remaining cap forward.
70	const runScenario = (scenario: Scenario): Result[] => {
71	  const policies = new Map<number, Policy>();
72	  let quoteCount = 0;
73	
74	  return scenario.steps.map((step, index) => {
75	    if (step.op === "quote") {
76	      const result = quote(scenario.customer, { items: step.items }, quoteCount);
77	      quoteCount += 1;
78	      policies.set(index, {
79	        items: step.items,
80	        remainingCap: policyCap(step.items),
81	      });
82	      return result;
83	    }
84	
85	    const policy = policies.get(step.policy);
86	    if (policy === undefined) {
87	      throw new Error(`claim references unknown policy step: ${step.policy}`);
88	    }
89	    const result = claim(policy.items, step.incident, policy.remainingCap);
90	    policy.remainingCap = result.remainingCap;
91	    return result;
92	  });
93	};
94	
95	const main = async (): Promise<void> => {
96	  const scenario: Scenario = JSON.parse(await readStdin());
97	  const results = runScenario(scenario);
98	  process.stdout.write(JSON.stringify({ results }));
99	};
100	
101	main().catch((error: unknown) => {
102	  const message = error instanceof Error ? error.message : String(error);
103	  process.stderr.write(`${message}\n`);
104	  process.exit(1);
105	});
